VALUES
  ('promotion-6f0ba476-moex-00245', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司 X1 年度銷貨$2,000,000，應收帳款總額減少$120,000，備抵損失增加$2,000，提列預 期信用減損損失$5,000，請問甲公司X1年度向客戶收取之現金為多少？', '["$1,877,000", "$1,995,000", "$2,117,000", "$2,122,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00246', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X1年10月1日承租一高級兩層樓店面，租期10年，自當日起每年10月1日支付年 租金$200,000予出租人，租約不可取消，另甲公司支付$5,000予房屋仲介商作為尋找到店面 之佣金。但近來因附近捷運施工，導致生意蕭條，故甲公司於X5年9月30日決定於其他地 方租用店面，原店面立即停止營運，且亦因地點不佳而無法轉租，導致無法帶來任何經濟效 益。假設公司適用前述事件之折現率為5%，對使用權資產採成本模式按直線法折舊。試分析 上述租賃合約對甲公司X5年損益之淨影響（不考慮所得稅之影響，答案四捨五入至元）：', '["淨利減少$1,146,822", "淨利減少$1,148,687", "淨利減少$1,187,468", "淨利減少$1,200,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00247', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年底以面額$1,500,000買入乙公司3年期、票面利率3%、每年12月31日付 息 1 次之公司債並分類為按攤銷後成本衡量之投資，有關該公司債的預期信用損失估計金 額如下： 12個月預期信用損失 存續期間預期信用損失 X1年底 $7,500 $18,000 X2年底 $39,000 $75,000 X3年底 $240,000 $240,000 若X2年底該債券的信用風險已顯著增加，且X3年底該債券已發生減損，則甲公司於X1、 X2、X3年度應認列之減損損失金額為何？', '["$7,500、$31,500、$201,000", "$7,500、$67,500、$165,000", "$7,500、$75,000、$240,000", "$18,000、$57,000、$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00248', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司成立於X1年初，並於當日購入一機器設備。X3年底調整後結帳前，甲公司決定於當 年度將該機器設備之折舊方法由直線法變更為年數合計法，但殘值及耐用年限之假設不變。 已知X2及X3年底未變更折舊方法前之比較資產負債表中，不動產、廠房及設備之累計折舊 分別為$3,000,000及$3,545,454，且該機器設備如果自始即採直線法較自始即採年數合計法之 折舊金額，X1年度少$5,000，X2年度少$3,750及X3年度少$2,500。試問X3年改採年數合 計法下，在比較資產負債表中X2及X3年底之累計折舊各分別為何？', '["X2年底$3,005,750；X3年底$3,556,704", "X2年底$3,000,000；X3年底$3,556,704", "X2年底$3,000,000；X3年底$3,547,954", "X2年底$3,000,000；X3年底$3,550,142"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00249', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲牧場採曆年制，其會計政策為對不動產、廠房及設備採成本模式衡量（以直線法提列折舊）， 對生物資產按公允價值減出售成本衡量。X3 年 2 月 1 日開始建造一排泄物處理設施，投入 $600,000，5月1日完工估計可用20年，無殘值。7月1日以$21,000購入3匹馬供觀賞用 （另支付市場與牧場間運費$3,000），估計出售成本為$1,000；該等馬匹預估15年後處分，無 殘值，12月31日之公允價值為＄25,000，估計出售成本為$1,000。12月31日再以$15,000購 入5頭小牛（另支付市場與牧場間運費$3,000），估計若於當日出售須負擔運費$3,000及出售 成本為$1,000；該等牛隻預估2年後可長大出售，估計出售成本為$1,000。試問上列交易對甲 牧場X3年度本期淨利的影響為何？', '["淨減少$24,800", "淨減少$25,600", "淨減少$27,800", "淨減少$42,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "443c581d0f55", "answer_pdf_sha1": "629a83ee7439", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00250', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'essay', '甲在某律師事務所擔任受僱律師，乙則在公立醫院中擔任住院醫師，兩
人均屬於境內居住者，各自均獲有來自於工作亦即職業的所得。兩人在
結婚共同居住生活三年後，終於迎來所生子女丙，並且共同扶養之。甲
與乙在進行婚後第三年之綜合所得稅的年度結算申報時，提出以下主
張，請附理由說明，判斷其主張是否有理？
甲與乙兩人在婚後，仍得依照個人意願，將各自獲有來自於工作職業
的所得，分開而作綜合所得稅的結算申報？（10分）
甲之職業為律師、乙之職業為醫師，因為律師與醫師均屬稅法的執行
業務者，故而兩人均得以「執行業務所得」的所得類型，作綜合所得
稅的結算申報？（10分）
因甲與乙兩人共同扶養未成年子女丙，故而關於丙作為受扶養親屬之
免稅額與相關之扣除額，兩人各自均可計算一半之數額，由甲與乙各
自在個人綜合所得稅之結算申報中作減除？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00251', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'essay', '自然人 A 擔任 B 營利事業之負責人，因 B 營利事業欠繳營利事業所得
稅款並未繳納，旋遭該管稽徵機關作成保全處分，除對 B營利事業名下
相當於欠繳稅款之財產，通知有關機關，作不得為移轉或設定他項權利
登記以外，另又對於 A負責人通知，限制 A出入國境。A對該管稅捐稽
徵機關所為移轉或設定登記之限制與限制出境的通知，感到不服，欲提
起救濟。請附理由說明，以下敘述是否正確？
本件分別涉及應納稅款給付與稅款保全措施，依照我國稅法規定，均
應先向原處分之該管稽徵機關申請提起復查，對於復查決定若有不服
時，才能繼續提起訴願與行政訴訟程序？（10 分）
A認為，該管稽徵機關對 B營利事業之財產為限制移轉或設定他項權
利登記，又對於A限制出境，係屬於雙重處罰，違反法治國「一行為
不二罰」原則？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00252', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '下列有關我國所得稅法相關課稅規定之敘述何者正確？', '["凡有中華民國來源所得之個人，應就其中華民國來源之所得，課徵綜合所得稅", "來臺灣工作的外籍勞工，因為是外國人，所以不用課徵所得稅", "在臺灣居住滿183天的外籍看護，其取得我國境內來源所得應採就源扣繳完稅", "在臺灣有戶籍但其生活重心在境外的華僑，在我國境內要居住滿183天才需要辦理結算申報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00253', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '下列有關我國所得稅法相關課稅規定之敘述何者錯誤？', '["個人因繼承、遺贈或贈與而取得之財產免納所得稅", "個人取自營利事業贈與之財產免納所得稅以避免重複課稅", "個人出售家庭日常使用之衣物、家具免納所得稅", "教育、文化、公益、慈善機關或團體，符合行政院規定標準者，其本身及其附屬作業組織之所 得免納所得稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00254', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-110-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '老張在民國108年12月簽約購買預售屋一戶，若於110年3月未交屋前售出，試問老張應如何 申報相關之所得稅？', '["老張須於110年5月31日以前申報綜合所得稅", "老張只須就房屋交易所得課稅，土地交易所得免稅", "老張須於111年5月31日以前申報綜合所得稅", "老張須於簽訂預售屋出售合約之次日起算 30 日內自行填具申報書，檢附契約書影本及其他有 關文件，向該管稽徵機關辦理申報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:30+00:00", "source_pdf_sha1": "c9b7c0fd19e2", "answer_pdf_sha1": "12106142af95", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "118", "s": "0512", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
